import React, { useRef } from 'react';
import { motion, useInView } from 'framer-motion';
import UmbrellaProject from './UmbrellaProject';
import ProjectCard from './ProjectCard';
import { projects } from '../data/portfolioData';

export default function Projects() {
  const ref = useRef(null);
  const isInView = useInView(ref, { once: true, margin: '-100px' });

  return (
    <section id="projects" className="py-28 px-6">
      <div className="max-w-7xl mx-auto">
        {/* Section header */}
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 20 }}
          animate={isInView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
          className="text-center mb-16"
        >
          <span className="font-mono text-[#6c63ff] text-sm tracking-widest uppercase">// work</span>
          <h2 className="font-space text-4xl md:text-5xl font-bold text-white mt-3 mb-4">
            Featured Projects
          </h2>
          <p className="text-slate-400 max-w-xl mx-auto">
            Production-grade AI systems spanning agentic pipelines, LLM safety infrastructure,
            and causal machine learning.
          </p>
        </motion.div>

        {/* Featured umbrella project */}
        <UmbrellaProject />

        {/* Two-column project cards */}
        <div className="grid md:grid-cols-2 gap-6">
          {projects.slice(1).map((project, i) => (
            <ProjectCard key={project.id} project={project} index={i} />
          ))}
        </div>
      </div>
    </section>
  );
}
